module.render:
const gap = args.gap || '1.5rem';
const items = sections.filter(function (s) { return s.trim().length > 0; });
const count = parseInt(args.count, 10) || items.length || 2;
const basis = (100 / count);
let html = `\n\n<div class="mdp-mod-columns" style="gap: ${gap};">\n`;
items.forEach(function (section) {
  const contentStr = section.trim();
  html += `<div class="mdp-mod-columns-col" style="flex: 0 0 calc(${basis}% - ${gap}); max-width: calc(${basis}% - ${gap});">\n\n${contentStr}\n\n</div>`;
});
html += `</div>\n\n`;
return html;
